package com.google.gson.stream;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonWriter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

public class JsonWriterTest {

    private JsonWriter jsonWriter;
    private StringWriter stringWriter;

    @BeforeEach
    public void setUp() {
        stringWriter = new StringWriter();
        jsonWriter = new JsonWriter(stringWriter);
    }

    @Test
    public void testWriteDeferredName_NullDeferredName() throws Exception {
        // deferredName is null by default, so just invoke writeDeferredName and expect no exception
        Method writeDeferredName = JsonWriter.class.getDeclaredMethod("writeDeferredName");
        writeDeferredName.setAccessible(true);

        // Should not throw and output should be empty
        writeDeferredName.invoke(jsonWriter);
        assertEquals("", stringWriter.toString());
    }

    @Test
    public void testWriteDeferredName_WithDeferredName() throws Exception {
        // Set deferredName field to a non-null value using reflection
        Field deferredNameField = JsonWriter.class.getDeclaredField("deferredName");
        deferredNameField.setAccessible(true);
        deferredNameField.set(jsonWriter, "testName");

        // Spy on jsonWriter to verify method calls
        JsonWriter spyWriter = Mockito.spy(jsonWriter);

        // Replace deferredName in spyWriter as well
        deferredNameField.set(spyWriter, "testName");

        Method writeDeferredName = JsonWriter.class.getDeclaredMethod("writeDeferredName");
        writeDeferredName.setAccessible(true);

        // Instead of mocking private methods, use reflection to intercept calls by temporarily replacing them with no-ops
        // Backup original methods
        Method beforeNameMethod = JsonWriter.class.getDeclaredMethod("beforeName");
        beforeNameMethod.setAccessible(true);
        Method stringMethod = JsonWriter.class.getDeclaredMethod("string", String.class);
        stringMethod.setAccessible(true);

        // Create a proxy JsonWriter subclass to override private methods via reflection is impossible,
        // so we invoke writeDeferredName normally on spyWriter and verify effects indirectly.

        // Invoke writeDeferredName on spyWriter
        writeDeferredName.invoke(spyWriter);

        // Since private methods cannot be verified directly, verify the effect by checking deferredName is null
        assertNull(deferredNameField.get(spyWriter));

        // Also check the output contains the expected string (JSON string with "testName")
        String output = stringWriter.toString();
        assertTrue(output.contains("\"testName\""), "Output should contain the deferred name as a JSON string");
    }
}
